(window.webpackJsonp=window.webpackJsonp||[]).push([[798],{790:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">cardPoints</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxScore = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">cardPoints, k</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> len=cardPoints.length\\n  <span class=\\"hljs-keyword\\">if</span>(k&gt;=len)<span class=\\"hljs-keyword\\">return</span> cardPoints.reduce(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a+b)\\n  <span class=\\"hljs-keyword\\">let</span> left=cardPoints.slice(<span class=\\"hljs-number\\">0</span>,k)\\n  <span class=\\"hljs-keyword\\">let</span> right=cardPoints.slice(len-k)\\n  <span class=\\"hljs-keyword\\">let</span> leftSum=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> rightSum=right.reduce(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a+b)\\n  <span class=\\"hljs-keyword\\">let</span> max=rightSum\\n  <span class=\\"hljs-comment\\">// console.log(left,right)</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;k;i++){\\n    leftSum+=left[i]\\n    rightSum-=right[i]\\n    <span class=\\"hljs-comment\\">// res+=getSum(left.slice(0,i))</span>\\n    <span class=\\"hljs-comment\\">// res+=getSum(right.slice(i,right.length))</span>\\n    \\n    max=<span class=\\"hljs-built_in\\">Math</span>.max(max,leftSum+rightSum)\\n    <span class=\\"hljs-comment\\">// console.log(max,i)</span>\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> max\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">getSum</span>(<span class=\\"hljs-params\\">arr</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> s=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> n <span class=\\"hljs-keyword\\">of</span> arr){\\n      s+=n\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> s\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"maximum-points-you-can-obtain-from-cards","hasThinking":false,"content":"<p>\u51e0\u5f20\u5361\u724c<strong> \u6392\u6210\u4e00\u884c</strong>\uff0c\u6bcf\u5f20\u5361\u724c\u90fd\u6709\u4e00\u4e2a\u5bf9\u5e94\u7684\u70b9\u6570\u3002\u70b9\u6570\u7531\u6574\u6570\u6570\u7ec4 <code>cardPoints</code> \u7ed9\u51fa\u3002</p>\\n\\n<p>\u6bcf\u6b21\u884c\u52a8\uff0c\u4f60\u53ef\u4ee5\u4ece\u884c\u7684\u5f00\u5934\u6216\u8005\u672b\u5c3e\u62ff\u4e00\u5f20\u5361\u724c\uff0c\u6700\u7ec8\u4f60\u5fc5\u987b\u6b63\u597d\u62ff <code>k</code> \u5f20\u5361\u724c\u3002</p>\\n\\n<p>\u4f60\u7684\u70b9\u6570\u5c31\u662f\u4f60\u62ff\u5230\u624b\u4e2d\u7684\u6240\u6709\u5361\u724c\u7684\u70b9\u6570\u4e4b\u548c\u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>cardPoints</code> \u548c\u6574\u6570 <code>k</code>\uff0c\u8bf7\u4f60\u8fd4\u56de\u53ef\u4ee5\u83b7\u5f97\u7684\u6700\u5927\u70b9\u6570\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>cardPoints = [1,2,3,4,5,6,1], k = 3\\n<strong>\u8f93\u51fa\uff1a</strong>12\\n<strong>\u89e3\u91ca\uff1a</strong>\u7b2c\u4e00\u6b21\u884c\u52a8\uff0c\u4e0d\u7ba1\u62ff\u54ea\u5f20\u724c\uff0c\u4f60\u7684\u70b9\u6570\u603b\u662f 1 \u3002\u4f46\u662f\uff0c\u5148\u62ff\u6700\u53f3\u8fb9\u7684\u5361\u724c\u5c06\u4f1a\u6700\u5927\u5316\u4f60\u7684\u53ef\u83b7\u5f97\u70b9\u6570\u3002\u6700\u4f18\u7b56\u7565\u662f\u62ff\u53f3\u8fb9\u7684\u4e09\u5f20\u724c\uff0c\u6700\u7ec8\u70b9\u6570\u4e3a 1 + 6 + 5 = 12 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>cardPoints = [2,2,2], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u65e0\u8bba\u4f60\u62ff\u8d77\u54ea\u4e24\u5f20\u5361\u724c\uff0c\u53ef\u83b7\u5f97\u7684\u70b9\u6570\u603b\u662f 4 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>cardPoints = [9,7,7,9,7,7,9], k = 7\\n<strong>\u8f93\u51fa\uff1a</strong>55\\n<strong>\u89e3\u91ca\uff1a</strong>\u4f60\u5fc5\u987b\u62ff\u8d77\u6240\u6709\u5361\u724c\uff0c\u53ef\u4ee5\u83b7\u5f97\u7684\u70b9\u6570\u4e3a\u6240\u6709\u5361\u724c\u7684\u70b9\u6570\u4e4b\u548c\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>cardPoints = [1,1000,1], k = 1\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u4f60\u65e0\u6cd5\u62ff\u5230\u4e2d\u95f4\u90a3\u5f20\u5361\u724c\uff0c\u6240\u4ee5\u53ef\u4ee5\u83b7\u5f97\u7684\u6700\u5927\u70b9\u6570\u4e3a 1 \u3002 \\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>cardPoints = [1,79,80,1,1,1,200,1], k = 3\\n<strong>\u8f93\u51fa\uff1a</strong>202\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= cardPoints.length &lt;= 10^5</code></li>\\n\\t<li><code>1 &lt;= cardPoints[i] &lt;= 10^4</code></li>\\n\\t<li><code>1 &lt;= k &lt;= cardPoints.length</code></li>\\n</ul>\\n","title":"1423. \u53ef\u83b7\u5f97\u7684\u6700\u5927\u70b9\u6570","relatedTags":["\u6570\u7ec4","\u52a8\u6001\u89c4\u5212","Sliding Window"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1423"}')}}]);